from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, prevprime, nextprime
def A147516_gen(): # generator of terms when the first n terms are desired
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        for p in ps:
            if p == 3 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        mp = m*nextprime(max(ps.keys(),default=2))
        if mp not in hset:
            heappush(h,mp)
            hset.add(mp)
A147516_list = list(islice(A147516_gen(),40)) # _Chai Wah Wu_, Mar 23 2026

